68	PsiMsDaq_RetCode_t CheckStrDisabled(	PsiMsDaq_IpHandle ipHandle,
69											const uint8_t streamNr)
70	{
71		uint32_t strEna;
72		SAFE_CALL(PsiMsDaq_RegRead(ipHandle, PSI_MS_DAQ_REG_STRENA, &strEna));
73		if (strEna & (1 << streamNr)) {
74			return PsiMsDaq_RetCode_StrNotDisabled;
75		}
76		return PsiMsDaq_RetCode_Success;
77	}
