264	PsiMsDaq_RetCode_t PsiMsDaq_Str_Configure(	PsiMsDaq_StrHandle strHndl,
265												PsiMsDaq_StrConfig_t* const config_p)
266	{
267		//Pointer Cast
268		PsiMsDaq_StrInst_t* inst_p = (PsiMsDaq_StrInst_t*) strHndl;
269		PsiMsDaq_IpHandle ipHandle = inst_p->ipHandle;
270		PsiMsDaq_Inst_t* ipInst_p = (PsiMsDaq_Inst_t*) ipHandle;
271		const uint8_t strNr = inst_p->nr;
272		//Checks
273		if (0 != (config_p->streamWidthBits % 8)){
274			return PsiMsDaq_RetCode_IllegalStrWidth;
275		}
276		if (config_p->winCnt > ipInst_p->maxWindows) {
277			return PsiMsDaq_RetCode_IllegalWinCnt;
278		}
279		if (0 != (config_p->winSize % (config_p->streamWidthBits/8))) {
280			return PsiMsDaq_RetCode_WinSizeMustBeMultipleOfSamples;
281		}
282		SAFE_CALL(CheckStrDisabled(ipHandle, strNr));
283		//Set register values
284		SAFE_CALL(PsiMsDaq_RegWrite(ipHandle,
285									PSI_MS_DAQ_REG_POSTTRIG(strNr),
286									config_p->postTrigSamples));
287		SAFE_CALL(PsiMsDaq_RegSetField(	ipHandle,
288										PSI_MS_DAQ_REG_MODE(strNr),
289										PSI_MS_DAQ_REG_MODE_LSB_RECM,
290										PSI_MS_DAQ_REG_MODE_MSB_RECM,
291										config_p->recMode));
292		SAFE_CALL(PsiMsDaq_RegSetBit( 	ipHandle,
293										PSI_MS_DAQ_CTX_SCFG(strNr),
294										PSI_MS_DAQ_CTX_SCFG_BIT_RINGBUF,
295										config_p->winAsRingbuf));
296		SAFE_CALL(PsiMsDaq_RegSetBit( 	ipHandle,
297										PSI_MS_DAQ_CTX_SCFG(strNr),
298										PSI_MS_DAQ_CTX_SCFG_BIT_OVERWRITE,
299										config_p->winOverwrite));
300		SAFE_CALL(PsiMsDaq_RegWrite(ipHandle,
301									PSI_MS_DAQ_CTX_BUFSTART(strNr),
302									config_p->bufStartAddr));
303		SAFE_CALL(PsiMsDaq_RegWrite(ipHandle,
304									PSI_MS_DAQ_CTX_WINSIZE(strNr),
305									config_p->winSize));
306		SAFE_CALL(PsiMsDaq_RegSetField(	ipHandle,
307										PSI_MS_DAQ_CTX_SCFG(strNr),
308										PSI_MS_DAQ_CTX_SCFG_LSB_WINCNT,
309										PSI_MS_DAQ_CTX_SCFG_MSB_WINCNT,
310										config_p->winCnt-1));
311		//Set data structure values
312		inst_p->widthBytes = config_p->streamWidthBits/8;
313		inst_p->isConfigured = true;
314		inst_p->windows = config_p->winCnt;
315		inst_p->bufStart = config_p->bufStartAddr;
316		inst_p->postTrig = config_p->postTrigSamples;
317		inst_p->winSize = config_p->winSize;
318		//Done
319		return PsiMsDaq_RetCode_Success;
320	}
