421	PsiMsDaq_RetCode_t PsiMsDaq_Str_GetFreeWindows(	PsiMsDaq_StrHandle strHndl,
422													uint8_t* const freeWindows_p)
423	{
424		//Pointer Cast
425		PsiMsDaq_StrInst_t* inst_p = (PsiMsDaq_StrInst_t*) strHndl;
426		PsiMsDaq_IpHandle ipHandle = inst_p->ipHandle;
427		PsiMsDaq_Inst_t* ip_p = (PsiMsDaq_Inst_t*) ipHandle;
428		const uint8_t strNr = inst_p->nr;
429		//Implementation (looping is not very efficient but safe and simple)
430		uint8_t freeWin = 0;
431		for (int win = inst_p->windows-1; win > 0; win--) {
432			uint32_t cnt;
433			SAFE_CALL(PsiMsDaq_RegGetField(	ipHandle,
434											PSI_MS_DAQ_WIN_WINCNT(strNr, win, ip_p->strAddrOffs),
435											PSI_MS_DAQ_WIN_WINCNT_LSB_CNT,
436											PSI_MS_DAQ_WIN_WINCNT_MSB_CNT,
437											&cnt))
438			if (0 == cnt) {
439				freeWin++;
440			}
441		}
442		*freeWindows_p = freeWin;
443		//Done
444		return PsiMsDaq_RetCode_Success;
445	}
