509	PsiMsDaq_RetCode_t PsiMsDaq_StrWin_GetNoOfSamples(	PsiMsDaq_WinInfo_t winInfo,
510														uint32_t* const noOfSamples_p)
511	{
512		//Pointer Case
513		PsiMsDaq_Inst_t* ip_p = (PsiMsDaq_Inst_t*)winInfo.ipHandle;
514		//Setup
515		uint8_t strNr;
516		SAFE_CALL(PsiMsDaq_Str_GetStrNr(winInfo.strHandle, &strNr));
517		//Checks
518		SAFE_CALL(CheckStrNr(winInfo.ipHandle, strNr))
519		SAFE_CALL(CheckWinNr(winInfo.strHandle, winInfo.winNr))
520		//Implementation
521		SAFE_CALL(PsiMsDaq_RegGetField(	winInfo.ipHandle,
522										PSI_MS_DAQ_WIN_WINCNT(strNr, winInfo.winNr, ip_p->strAddrOffs),
523										PSI_MS_DAQ_WIN_WINCNT_LSB_CNT,
524										PSI_MS_DAQ_WIN_WINCNT_MSB_CNT,
525										noOfSamples_p));
526		//Done
527		return PsiMsDaq_RetCode_Success;
528	}
