530	PsiMsDaq_RetCode_t PsiMsDaq_StrWin_GetPreTrigSamples(	PsiMsDaq_WinInfo_t winInfo,
531															uint32_t* const preTrigSamples_p)
532	{
533		//Setup
534		PsiMsDaq_StrInst_t* str_p = (PsiMsDaq_StrInst_t*) winInfo.strHandle;
535		PsiMsDaq_Inst_t* ip_p = (PsiMsDaq_Inst_t*)winInfo.ipHandle;
536		//Checks
537		bool containsTrig;
538		SAFE_CALL(PsiMsDaq_RegGetBit(	winInfo.ipHandle,
539										PSI_MS_DAQ_WIN_WINCNT(str_p->nr, winInfo.winNr, ip_p->strAddrOffs),
540										PSI_MS_DAQ_WIN_WINCNT_BIT_ISTRIG,
541										&containsTrig))
542		if (!containsTrig) {
543			return PsiMsDaq_RetCode_NoTrigInWin;
544		}
545		//Implementation
546		uint32_t samples;
547		SAFE_CALL(PsiMsDaq_StrWin_GetNoOfSamples(winInfo, &samples));
548		*preTrigSamples_p = samples-str_p->postTrig;
549		//Done
550		return PsiMsDaq_RetCode_Success;
551	}
