553	PsiMsDaq_RetCode_t PsiMsDaq_StrWin_GetTimestamp(	PsiMsDaq_WinInfo_t winInfo,
554														uint64_t* const timestamp_p)
555	{
556		//Setup
557		uint8_t strNr;
558		SAFE_CALL(PsiMsDaq_Str_GetStrNr(winInfo.strHandle, &strNr));
559		PsiMsDaq_Inst_t* ip_p = (PsiMsDaq_Inst_t*)winInfo.ipHandle;
560		//Checks
561		bool containsTrig;
562		SAFE_CALL(PsiMsDaq_RegGetBit(	winInfo.ipHandle,
563										PSI_MS_DAQ_WIN_WINCNT(strNr, winInfo.winNr, ip_p->strAddrOffs),
564										PSI_MS_DAQ_WIN_WINCNT_BIT_ISTRIG,
565										&containsTrig))
566		if (!containsTrig) {
567			return PsiMsDaq_RetCode_NoTrigInWin;
568		}
569		//Implementation
570		uint32_t tsLo;
571		uint32_t tsHi;
572		SAFE_CALL(PsiMsDaq_RegRead(winInfo.ipHandle, PSI_MS_DAQ_WIN_TSLO(strNr, winInfo.winNr, ip_p->strAddrOffs), &tsLo));
573		SAFE_CALL(PsiMsDaq_RegRead(winInfo.ipHandle, PSI_MS_DAQ_WIN_TSHI(strNr, winInfo.winNr, ip_p->strAddrOffs), &tsHi));
574		*timestamp_p = (((uint64_t)tsHi) << 32) + tsLo;
575		//Done
576		return PsiMsDaq_RetCode_Success;
577	}
