743											const uint32_t addr,
744											uint32_t* const value_p)
745	{
746		//Cast pointer
747		PsiMsDaq_Inst_t* inst_p = (PsiMsDaq_Inst_t*)ipHandle;
748		//Execute access
749		*value_p = inst_p->regRdFct(inst_p->baseAddr+addr);
