754	PsiMsDaq_RetCode_t PsiMsDaq_RegSetField(	PsiMsDaq_IpHandle ipHandle,
755												const uint32_t addr,
756												const uint8_t lsb,
757												const uint8_t msb,
758												const uint32_t value)
759	{
760		//Execute access
761		uint32_t reg;
762		uint32_t msk = (1 << (msb+1))-1;
763		uint32_t mskSft = msk << lsb;
764		uint32_t valSft = ((value & msk) << lsb);
765		SAFE_CALL(PsiMsDaq_RegRead(ipHandle, addr, &reg));
766		reg &= ~mskSft;
767		reg |= valSft;
768		SAFE_CALL(PsiMsDaq_RegWrite(ipHandle, addr, reg));
769		//Done
770		return PsiMsDaq_RetCode_Success;
771	}
772	
773	PsiMsDaq_RetCode_t PsiMsDaq_RegGetField(	PsiMsDaq_IpHandle ipHandle,
774												const uint32_t addr,
775												const uint8_t lsb,
776												const uint8_t msb,
777												uint32_t* const value_p)
778	{
779		//Execute access
780		uint32_t reg;
781		uint32_t msk = (1 << (msb+1))-1;
782		SAFE_CALL(PsiMsDaq_RegRead(ipHandle, addr, &reg));
783		*value_p = (reg >> lsb) & msk;
784		//Done
785		return PsiMsDaq_RetCode_Success;
786	}
